	.ascii	"\344\270\200\344\270\252\346\267\261\347\201\260\350"
	.ascii	"\211\262\347\232\204\345\205\250\345\261\217\350\203"
	.ascii	"\214\346\231\257\012        aurora.fill_rect(0, 0, "
	.ascii	"128, 128, 0x18E3) \012    end\012\012    -- auroraO"
	.ascii	"S \345\260\217\347\250\213\345\272\217\347\224\237\345"
	.ascii	"\221\275\345\221\250\346\234\237\345\207\275\346\225"
	.ascii	"\260\357\274\232\346\257\217\345\270\247\345\210\267"
	.ascii	"\346\226\260\346\227\266\350\260\203\347\224\250\012"
	.ascii	"    function on_update()\012        local hr = auro"
	.ascii	"ra.get_heart_rate()\012        aurora.print(\"Curre"
	.ascii	"nt HR read by Lua: \" .. tostring(hr))\012        \012"
	.ascii	"        -- \346\240\271\346\215\256\345\277\203\347"
	.ascii	"\216\207\347\232\204\346\225\260\345\200\274\345\212"
