	.ascii	"\237\261\347\212\266\345\233\276\012        local b"
	.ascii	"ar_height = hr\012        if bar_height > 100 then "
	.ascii	"bar_height = 100 end\012        \012        -- \345"
	.ascii	"\205\210\347\224\250\351\273\221\350\211\262\346\223"
	.ascii	"\246\351\231\244\346\227\247\347\232\204\346\237\261"
	.ascii	"\347\212\266\345\233\276\345\214\272\345\237\237\012"
	.ascii	"        aurora.fill_rect(50, 20, 20, 100, 0x0000)\012"
	.ascii	"        \012        -- \347\224\273\345\207\272\346"
	.ascii	"\226\260\347\232\204\347\272\242\350\211\262\346\237"
	.ascii	"\261\345\275\242 (\344\273\216\345\272\225\351\203\250"
	.ascii	"\345\220\221\344\270\212\347\224\273)\012        lo"
	.ascii	"cal y_pos = 128 - bar_height\012        aurora.fill"
